query GetWorkspaceFonts($workspaceId: ID, $archived: Boolean, $sortBy: FontSortOrder) {
  fonts(workspaceId: $workspaceId, archived: $archived, sortBy: $sortBy) {
    ...Font
    __typename
  }
}

fragment Font on Font {
  id
  name
  cssUrl
  fontFiles {
    id
    name
    weight
    isItalic
    fileType
    sourceUrl
    __typename
  }
  workspaceId
  archived
  fontFileCount
  isDefault
  __typename
}
